import React, { useState, useEffect } from 'react';
import { useNavigate, useSearchParams, Outlet } from 'react-router-dom';
import { api } from '../api/client';

interface NavItem {
  id: string;
  label: string;
  path: string;
  icon: string;
  children?: NavItem[];
}

interface Theme {
  spacing: { sm: number; md: number; lg: number };
  colors: { bg: string; sidebar: string; text: string; accent: string };
}

interface DashboardLayoutProps {
  userId: string;
  theme: Theme;
}

export function DashboardLayout({ userId, theme }: DashboardLayoutProps) {
  const [navItems, setNavItems] = useState<NavItem[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isMobile, setIsMobile] = useState(window.innerWidth < 768);
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();

  useEffect(() => {
    api.get(`/users/${userId}/navigation`).then(setNavItems);
  }, []);

  useEffect(() => {
    const redirect = searchParams.get('redirect');
    if (redirect) {
      navigate(redirect);
    }
  }, [searchParams, navigate]);

  useEffect(() => {
    const handleResize = () => {
      const mobile = window.innerWidth < 768;
      setIsMobile(mobile);
      if (mobile) setIsSidebarOpen(false);
    };

    window.addEventListener('resize', handleResize);
  }, []);

  const renderNavItem = (item: NavItem) => (
    <li key={item.id}>
      <a
        href={item.path}
        onClick={(e) => {
          e.preventDefault();
          navigate(item.path);
          if (isMobile) setIsSidebarOpen(false);
        } }
        style={ { padding: theme.spacing.sm, color: theme.colors.text } }
      >
        <span className="nav-icon">{item.icon}</span>
        {isSidebarOpen && <span className="nav-label">{item.label}</span>}
      </a>
      {item.children && isSidebarOpen && (
        <ul className="sub-nav">
          {item.children.map(child => renderNavItem(child))}
        </ul>
      )}
    </li>
  );

  const breadcrumbs = window.location.pathname
    .split('/')
    .filter(Boolean)
    .map((segment, i, arr) => ({
      label: segment.charAt(0).toUpperCase() + segment.slice(1),
      path: '/' + arr.slice(0, i + 1).join('/'),
    }));

  return (
    <div
      className="dashboard-layout"
      style={ { display: 'flex', minHeight: '100vh', backgroundColor: theme.colors.bg } }
    >
      <aside
        className={`sidebar ${isSidebarOpen ? 'open' : 'collapsed'}`}
        style={ {
          width: isSidebarOpen ? 240 : 60,
          backgroundColor: theme.colors.sidebar,
          padding: theme.spacing.md,
          transition: 'width 0.2s ease',
        } }
      >
        <button
          onClick={() => setIsSidebarOpen(!isSidebarOpen)}
          className="sidebar-toggle"
        >
          {isSidebarOpen ? 'Collapse' : 'Expand'}
        </button>
        <nav>
          <ul>{navItems.map(item => renderNavItem(item))}</ul>
        </nav>
      </aside>
      <main
        style={ {
          flex: 1,
          padding: theme.spacing.md,
          backgroundColor: theme.colors.bg,
        } }
      >
        <div className="breadcrumbs" style={ { marginBottom: theme.spacing.md } }>
          {breadcrumbs.map((crumb, i) => (
            <span key={crumb.path}>
              {i > 0 && ' / '}
              <a
                href={crumb.path}
                onClick={(e) => { e.preventDefault(); navigate(crumb.path); } }
                style={ { color: theme.colors.accent } }
              >
                {crumb.label}
              </a>
            </span>
          ))}
        </div>
        <Outlet />
      </main>
    </div>
  );
}

