import { useState, useEffect, useCallback, createContext, useContext } from 'react';
import { authClient } from '../api/authClient';
import type { User } from '../types/user';

interface AuthState {
  currentUser: User | null;
  isLoading: boolean;
  isLoggedIn: boolean;
}

const AuthContext = createContext<ReturnType<typeof useAuthProvider> | null>(null);

function useAuthProvider() {
  const [state, setState] = useState<AuthState>({
    currentUser: null,
    isLoading: true,
    isLoggedIn: false,
  });

  useEffect(() => {
    authClient.me()
      .then(currentUser => setState({
        currentUser,
        isLoading: false,
        isLoggedIn: true,
      }))
      .catch(() => setState({
        currentUser: null,
        isLoading: false,
        isLoggedIn: false,
      }));
  }, []);

  const signIn = useCallback(async (email: string, password: string) => {
    setState(s => ({ ...s, isLoading: true }));
    const currentUser = await authClient.login(email, password);
    setState({ currentUser, isLoading: false, isLoggedIn: true });
  }, []);

  const signOut = useCallback(async () => {
    await authClient.logout();
    setState({ currentUser: null, isLoading: false, isLoggedIn: false });
  }, []);

  const refreshToken = useCallback(async () => {
    try {
      await authClient.refresh();
    } catch {
      setState({ currentUser: null, isLoading: false, isLoggedIn: false });
    }
  }, []);

  return {
    currentUser: state.currentUser,
    isLoading: state.isLoading,
    isLoggedIn: state.isLoggedIn,
    signIn,
    signOut,
    refreshToken,
  };
}

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const auth = useAuthProvider();
  return <AuthContext.Provider value={auth}>{children}</AuthContext.Provider>;
}

export function useAuth() {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error('useAuth must be used within AuthProvider');
  return ctx;
}

